    const dependencyLine = page.locator('.dependency-line, [data-dependency], .gantt-dependency').first();

    if (await dependencyLine.isVisible({ timeout: 2000 }).catch(() => false)) {
      await expect(dependencyLine).toBeVisible();
    }

